+    #[test]
+    fn canonicalize_map_rejects_impossible_entry_cardinality_before_extra_allocation() {
+        let mut entries = vec![
+            (Value::Integer(0.into()), Value::Integer(0.into())),
+            (Value::Integer(1.into()), Value::Integer(1.into())),
